mapper.update:
UPDATE adm_meeting_room
SET room_name=#{roomName}, location=#{location}, capacity=#{capacity},
    has_projector=#{hasProjector}, has_microphone=#{hasMicrophone}, status=#{status}
WHERE id=#{id}

mapper.select:
SELECT COUNT(*) = 0 FROM adm_room_booking
WHERE room_id = #{roomId} AND status = 'BOOKED'
AND start_time < #{end} AND end_time > #{start}
